import React, { useState } from 'react';
import axios from "axios";

// import {config} from "dotenv";

const LoginPage = () => {
    // const [email, setEmail] = useState('');
    const [userName, setUserName] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    // config();
    // const apiUrl = process.env.BANK_APP_URL;
    const apiUrl = "10.10.0.95:3003/";

    const handleSubmit = async (e) => {
        console.log("handleSubmit", e);
        e.preventDefault();

        console.log("Login with:\nemail: " + userName + "\nPassword: " + password);

        if (!userName || !password) {
            setError('Please enter both userName and password');
            return;
        }

        setIsLoading(true);
        setError('');

        try {
            let response= await axios.post("http://localhost:3003/user/login", {
                username: userName,
                password: password
            })

            console.log("response is: " + response);

            if (200 !== response.status) {
                console.log("response.status: " + response.status);
                console.log("response.data: " + response.data);
                throw new Error('Login failed, please try again.');
            }

            // Handle successful login here (e.g., redirect to dashboard)
            console.log('Login successful');

            const { token, userData } = response.data;

            // Save the token and user data (maybe in localStorage or context)
            localStorage.setItem("authToken", token);
            localStorage.setItem("userData", JSON.stringify(userData));

            // Redirect to profile page
            history.push("/profile");
        } catch (err) {
            setError(err.message || 'An error occurred');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div style={styles.container}>
            <h2>Login to Your Account</h2>
            {error && <div style={styles.error}>{error}</div>}
            <form onSubmit={handleSubmit}>
                <div style={styles.inputContainer}>
                    <label>User Name</label>
                    <input
                        type="string"
                        value={userName}
                        onChange={(e) => setUserName(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your user name"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Password</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your password"
                    />
                </div>
                <button type="submit" style={styles.button} disabled={isLoading}>
                    {isLoading ? 'Logging in...' : 'Login'}
                </button>
            </form>
            <div style={styles.redirect}>
                <p>Don't have an account? <a href="/register">Register here</a></p>
            </div>
        </div>
    );
};

